contracts/SmartCampusComplaints.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SmartCampusComplaints
 * @dev Records and tracks complaint resolution for institutional accountability.
 */
contract SmartCampusComplaints is Ownable {

    struct ComplaintRecord {
        string complaintId;
        uint256 registeredAt;
        uint256 deadline;
        uint256 resolvedAt;
        bool isResolved;
    }

    mapping(string => ComplaintRecord) public complaints;

    event ComplaintRegistered(string indexed complaintId, uint256 deadline, uint256 timestamp);
    event ComplaintResolved(string indexed complaintId, uint256 timestamp);
    event ComplaintEscalated(string indexed complaintId, uint256 timestamp);

    constructor(address initialOwner) Ownable(initialOwner) {}

    /**
     * @dev Register a new complaint with a resolution deadline.
     */
    function registerComplaint(string calldata complaintId, uint256 deadline) external onlyOwner {
        require(complaints[complaintId].registeredAt == 0, "Complaint already exists");

        complaints[complaintId] = ComplaintRecord({
            complaintId: complaintId,
            registeredAt: block.timestamp,
            deadline: deadline,
            resolvedAt: 0,
            isResolved: false
        });

        emit ComplaintRegistered(complaintId, deadline, block.timestamp);
    }

    /**
     * @dev Resolve a complaint.
     */
    function resolveComplaint(string calldata complaintId) external onlyOwner {
        require(complaints[complaintId].registeredAt > 0, "Complaint does not exist");
        require(!complaints[complaintId].isResolved, "Complaint already resolved");

        ComplaintRecord storage record = complaints[complaintId];
        record.resolvedAt = block.timestamp;
        record.isResolved = true;

        if (block.timestamp > record.deadline) {
            emit ComplaintEscalated(complaintId, block.timestamp);
        }

        emit ComplaintResolved(complaintId, block.timestamp);
    }
}

contracts/SmartCampusLibrary.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SmartCampusLibrary
 * @dev Records book loans and returns for tampering-proof fine management.
 */
contract SmartCampusLibrary is Ownable {

    struct LoanRecord {
        string loanId;
        string isbn;
        string enrollmentNo;
        uint256 issuedAt;
        uint256 returnedAt;
        uint256 fineAmount;
        bool isReturned;
    }

    mapping(string => LoanRecord) public loans;

    event BookIssued(string indexed loanId, string isbn, string enrollmentNo);
    event BookReturned(string indexed loanId, uint256 fineAmount, uint256 timestamp);

    constructor(address initialOwner) Ownable(initialOwner) {}

    /**
     * @dev Record a book issue.
     */
    function recordLoan(string calldata loanId, string calldata isbn, string calldata enrollmentNo) external onlyOwner {
        require(loans[loanId].issuedAt == 0, "Loan already exists");

        loans[loanId] = LoanRecord({
            loanId: loanId,
            isbn: isbn,
            enrollmentNo: enrollmentNo,
            issuedAt: block.timestamp,
            returnedAt: 0,
            fineAmount: 0,
            isReturned: false
        });

        emit BookIssued(loanId, isbn, enrollmentNo);
    }

    /**
     * @dev Record a book return with optional fine.
     */
    function recordReturn(string calldata loanId, uint256 fineAmount) external onlyOwner {
        require(loans[loanId].issuedAt > 0, "Loan does not exist");
        require(!loans[loanId].isReturned, "Book already returned");

        LoanRecord storage record = loans[loanId];
        record.returnedAt = block.timestamp;
        record.fineAmount = fineAmount;
        record.isReturned = true;

        emit BookReturned(loanId, fineAmount, block.timestamp);
    }
}

contracts/SmartCampusReevaluation.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SmartCampusReevaluation
 * @dev Handles re-evaluation requests with an escrow system for fees.
 */
contract SmartCampusReevaluation is Ownable {

    struct ReevaluationRequest {
        string requestId;
        address student;
        uint256 fee;
        bool resolved;
        bool refunded;
        uint256 timestamp;
    }

    mapping(string => ReevaluationRequest) public requests;

    event ReevaluationApplied(string indexed requestId, address indexed student, uint256 fee);
    event ReevaluationResolved(string indexed requestId, bool refunded, uint256 amount);

    constructor(address initialOwner) Ownable(initialOwner) {}

    /**
     * @dev Apply for re-evaluation. The fee is held in escrow.
     * @param requestId The unique ID of the reassessment request from the database.
     */
    function applyForReevaluation(string calldata requestId) external payable {
        require(msg.value > 0, "Fee must be greater than 0");
        require(requests[requestId].fee == 0, "Request already exists");

        requests[requestId] = ReevaluationRequest({
            requestId: requestId,
            student: msg.sender,
            fee: msg.value,
            resolved: false,
            refunded: false,
            timestamp: block.timestamp
        });

        emit ReevaluationApplied(requestId, msg.sender, msg.value);
    }

    /**
     * @dev Resolve a re-evaluation request.
     * @param requestId The unique ID of the request.
     * @param shouldRefund Whether the fee should be refunded to the student.
     */
    function resolveReevaluation(string calldata requestId, bool shouldRefund) external onlyOwner {
        ReevaluationRequest storage req = requests[requestId];
        require(req.fee > 0, "Request does not exist");
        require(!req.resolved, "Request already resolved");

        req.resolved = true;

        if (shouldRefund) {
            req.refunded = true;
            (bool success, ) = payable(req.student).call{value: req.fee}("");
            require(success, "Refund failed");
            emit ReevaluationResolved(requestId, true, req.fee);
        } else {
            // Fee stays in the contract (university keeps it)
            // University admin can later withdraw these funds
            emit ReevaluationResolved(requestId, false, 0);
        }
    }

    /**
     * @dev Withdraw university funds.
     */
    function withdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "No funds to withdraw");
        (bool success, ) = payable(owner()).call{value: balance}("");
        require(success, "Withdrawal failed");
    }
}

